using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public sealed class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    [ColumnName("Label")]
    public string Category { get; set; } = string.Empty;
}

public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

public sealed class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public sealed class TicketResponse
{
    public required string PredictedCategory { get; set; }
    public required Dictionary<string, float> Confidence { get; set; }
}

public sealed class EvaluationMetricsResponse
{
    public float MicroAccuracy { get; set; }
    public float MacroAccuracy { get; set; }
    public float LogLoss { get; set; }
    public float LogLossReduction { get; set; }
    public required PerClassMetric[] PerClassMetrics { get; set; }
}

public sealed class PerClassMetric
{
    public required string Class { get; set; }
    public double Precision { get; set; }
    public double Recall { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketClassifierService
{
    private readonly MLContext _mlContext = new(seed: 42);
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<TicketClassifierService> _logger;

    private ITransformer? _model;
    private string[]? _classLabels;
    private EvaluationMetricsResponse? _cachedMetrics;

    public TicketClassifierService(ILogger<TicketClassifierService> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "ticket_model.zip");
    }

    public EvaluationMetricsResponse TrainAndEvaluate()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label")
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(split.TrainSet);
        _mlContext.Model.Save(_model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model trained and saved to {Path}", _modelPath);

        // Extract class labels from the key-value mapping
        var labelColumn = split.TrainSet.Schema["Label"];
        var keyType = labelColumn.Type as Microsoft.ML.Data.KeyDataViewType;
        if (keyType is not null)
        {
            var keyValues = new VBuffer<ReadOnlyMemory<char>>();
            labelColumn.GetKeyValues(ref keyValues);
            _classLabels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();
        }

        // Evaluate on test set
        var predictions = _model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation(
            "Evaluation — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
            metrics.MicroAccuracy, metrics.MacroAccuracy, metrics.LogLoss);

        var perClass = metrics.PerClassLogLoss
            .Select((_, i) => new PerClassMetric
            {
                Class = _classLabels is not null && i < _classLabels.Length
                    ? _classLabels[i]
                    : $"Class_{i}",
                Precision = i < metrics.ConfusionMatrix.PerClassPrecision.Count
                    ? metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                Recall = i < metrics.ConfusionMatrix.PerClassRecall.Count
                    ? metrics.ConfusionMatrix.PerClassRecall[i] : 0,
            })
            .ToArray();

        _cachedMetrics = new EvaluationMetricsResponse
        {
            MicroAccuracy = (float)metrics.MicroAccuracy,
            MacroAccuracy = (float)metrics.MacroAccuracy,
            LogLoss = (float)metrics.LogLoss,
            LogLossReduction = (float)metrics.LogLossReduction,
            PerClassMetrics = perClass,
        };

        return _cachedMetrics;
    }

    public EvaluationMetricsResponse? GetCachedMetrics() => _cachedMetrics;

    public string[] GetClassLabels() => _classLabels ?? ["Billing", "General", "Technical"];

    public ITransformer GetModel()
    {
        if (_model is not null) return _model;

        if (File.Exists(_modelPath))
        {
            _model = _mlContext.Model.Load(_modelPath, out _);
            _logger.LogInformation("Model loaded from {Path}", _modelPath);
            return _model;
        }

        TrainAndEvaluate();
        return _model!;
    }

    public DataViewSchema GetTrainingSchema()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
        return data.Schema;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public sealed class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly TicketClassifierService _classifierService;

    public TicketsController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        TicketClassifierService classifierService)
    {
        _predictionPool = predictionPool;
        _classifierService = classifierService;
    }

    /// <summary>POST /api/tickets/classify — predict category for a ticket.</summary>
    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionPool.Predict(input);
        var labels = _classifierService.GetClassLabels();
        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence,
        });
    }

    /// <summary>POST /api/tickets/train — retrain the model and return evaluation metrics.</summary>
    [HttpPost("train")]
    public ActionResult<EvaluationMetricsResponse> Train()
    {
        var metrics = _classifierService.TrainAndEvaluate();
        return Ok(metrics);
    }

    /// <summary>GET /api/tickets/metrics — return cached evaluation metrics.</summary>
    [HttpGet("metrics")]
    public ActionResult<EvaluationMetricsResponse> GetMetrics()
    {
        var metrics = _classifierService.GetCachedMetrics();
        if (metrics is null)
            return NotFound("Model has not been trained yet. POST /api/tickets/train first.");

        return Ok(metrics);
    }
}

