using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public sealed class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly TicketClassifierService _classifierService;

    public TicketsController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        TicketClassifierService classifierService)
    {
        _predictionPool = predictionPool;
        _classifierService = classifierService;
    }

    /// <summary>POST /api/tickets/classify — predict category for a ticket.</summary>
    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionPool.Predict(input);
        var labels = _classifierService.GetClassLabels();
        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence,
        });
    }

    /// <summary>POST /api/tickets/train — retrain the model and return evaluation metrics.</summary>
    [HttpPost("train")]
    public ActionResult<EvaluationMetricsResponse> Train()
    {
        var metrics = _classifierService.TrainAndEvaluate();
        return Ok(metrics);
    }

    /// <summary>GET /api/tickets/metrics — return cached evaluation metrics.</summary>
    [HttpGet("metrics")]
    public ActionResult<EvaluationMetricsResponse> GetMetrics()
    {
        var metrics = _classifierService.GetCachedMetrics();
        if (metrics is null)
            return NotFound("Model has not been trained yet. POST /api/tickets/train first.");

        return Ok(metrics);
    }
}

